            plunge: components["schemas"]["PlungeStrategy"];
            reverse: boolean;
            /** Format: double */
            start_depth: number;
            /**
             * Format: double
             * @description Per-pass z step (negative ⇒ down).
             */
            step: number;
            /**
             * Format: double
             * @description Cut past `depth` by this many mm (positive). Used for through-cuts on edge-clamped sheet.
             * @default 0
             */
            through_depth: number;
